Here's an example method that uses the DocX library to accomplish this:
```csharp
using Novacode;
using System.IO;
using System.Xml.Linq;
using System.Xml.XPath;

public void CreateDocxFromHtml(string inputHtml, string templateFilePath, string outputFilePath)
{
    // Load the docx template file
    using (DocX template = DocX.Load(templateFilePath))
    {
        // Parse the input HTML as XML
        XDocument html = XDocument.Parse(inputHtml);

        // Replace the placeholders in the template with the corresponding text from the input HTML
        foreach (XElement element in html.XPathSelectElements("//body/*"))
        {
            // Check if the element has any style attributes
            string style = "";
            XAttribute styleAttr = element.Attribute("style");
            if (styleAttr != null)
            {
                style = styleAttr.Value;
            }

            // Replace the relevant placeholder in the template with the element's text and style
            string text = element.Value;
            if (element.Name == "b")
            {
                text = text.Bold();
            }
            else if (element.Name == "i")
            {
                text = text.Italic();
            }
            else if (element.Name == "u")
            {
                text = text.Underline();
            }
            else if (element.Name == "ul")
            {
                // Convert the unordered list to a bullet list
                foreach (XElement li in element.Elements("li"))
                {
                    template.InsertList(li.Value, 0, ListItemType.Bulleted);
                }
                continue;
            }
            else if (element.Name == "ol")
            {
                // Convert the ordered list to a numbered list
                int count = 1;
                foreach (XElement li in element.Elements("li"))
                {
                    template.InsertList(li.Value, count++, ListItemType.Numbered);
                }
                continue;
            }

            template.ReplaceText($"#{element.Name}", text, false, System.Text.RegularExpressions.RegexOptions.None, new Formatting() { Bold = style.Contains("font-weight:bold"), Italic = style.Contains("font-style:italic"), UnderlineStyle = style.Contains("text-decoration:underline") ? UnderlineStyle.singleLine : UnderlineStyle.none });
        }

        // Save the final docx file
        template.SaveAs(outputFilePath);
    }
}
```
